import re
import json
import ast

def solve(packet: str) -> int:
    def clean_value(x):
        if x is None:
            return ""
        x = str(x).strip()
        if len(x) >= 2 and ((x[0] == x[-1] == '"') or (x[0] == x[-1] == "'")):
            x = x[1:-1]
        return x

    def checksum(payload, version):
        return (sum(ord(c) for c in payload) + int(version)) % 256

    s = packet.strip()

    for loader in (json.loads, ast.literal_eval):
        try:
            obj = loader(s)
            if isinstance(obj, dict):
                lower = {str(k).lower(): v for k, v in obj.items()}
                if "version" in lower and "payload" in lower:
                    return checksum(clean_value(lower["payload"]), int(lower["version"]))
                if "v" in lower and "payload" in lower:
                    return checksum(clean_value(lower["payload"]), int(lower["v"]))
                if "version" in lower and "data" in lower:
                    return checksum(clean_value(lower["data"]), int(lower["version"]))
            elif isinstance(obj, (list, tuple)) and len(obj) >= 2:
                if isinstance(obj[0], int):
                    return checksum(clean_value(obj[1]), obj[0])
                if isinstance(obj[1], int):
                    return checksum(clean_value(obj[0]), obj[1])
        except Exception:
            pass

    version_match = re.search(r'(?i)\b(?:version|ver|v)\s*[:=]\s*([+-]?\d+)\b', s)
    payload_match = re.search(r'(?i)\b(?:payload|data|body|msg|message)\s*[:=]\s*(.*?)(?=\s*(?:[,;|]\s*(?:version|ver|v|checksum|crc)\s*[:=]|\s*$))', s)
    if version_match and payload_match:
        return checksum(clean_value(payload_match.group(1)), int(version_match.group(1)))

    m = re.match(r'(?is)^\s*(?:fluxon|flux|fxn|pkt|packet)?\s*[/|:;,\-\s]*v(?:er(?:sion)?)?\s*([+-]?\d+)\s*[\]|/:;,\-\s]+\s*(.*?)\s*$', s)
    if m:
        payload = m.group(2)
        payload = re.sub(r'(?is)\s*[\]|/:;,\-\s]+(?:checksum|crc|sum)\s*[:=]?\s*[0-9a-fx+-]+\s*$', '', payload).strip()
        return checksum(clean_value(payload), int(m.group(1)))

    m = re.match(r'(?is)^\s*(?:fluxon|flux|fxn|pkt|packet)?\s*[/|:;,\-\s]*([+-]?\d+)\s*[\]|/:;,\-\s]+\s*(.*?)\s*$', s)
    if m:
        payload = m.group(2)
        payload = re.sub(r'(?is)\s*[\]|/:;,\-\s]+(?:checksum|crc|sum)\s*[:=]?\s*[0-9a-fx+-]+\s*$', '', payload).strip()
        return checksum(clean_value(payload), int(m.group(1)))

    m = re.match(r'(?is)^\s*(.*?)\s*[\]|/:;,\-\s]+\s*v(?:er(?:sion)?)?\s*([+-]?\d+)\s*$', s)
    if m:
        return checksum(clean_value(m.group(1)), int(m.group(2)))

    parts = [p.strip() for p in re.split(r'[|;,:]', s) if p.strip()]
    if len(parts) >= 2:
        def parse_ver(t):
            mt = re.fullmatch(r'(?i)v(?:er(?:sion)?)?\s*([+-]?\d+)', t)
            if mt:
                return int(mt.group(1))
            if re.fullmatch(r'[+-]?\d+', t):
                return int(t)
            return None

        for i, part in enumerate(parts):
            v = parse_ver(part)
            if v is not None:
                if i + 1 < len(parts):
                    payload_parts = parts[i + 1:]
                    if len(payload_parts) > 1 and re.fullmatch(r'(?i)(?:checksum|crc|sum)\s*=?\s*[0-9a-fx+-]+', payload_parts[-1]):
                        payload_parts = payload_parts[:-1]
                    elif len(payload_parts) > 1 and re.fullmatch(r'[0-9a-fx+-]+', payload_parts[-1]) and re.fullmatch(r'(?i)(?:checksum|crc|sum)', payload_parts[-2]):
                        payload_parts = payload_parts[:-2]
                    return checksum(clean_value(":".join(payload_parts)), v)
                if i > 0:
                    return checksum(clean_value(":".join(parts[:i])), v)

    nums = re.findall(r'[+-]?\d+', s)
    version = int(nums[0]) if nums else 0
    payload = s
    if nums:
        payload = re.sub(r'[+-]?\d+', '', payload, count=1).strip(" |:;,-")
    return checksum(clean_value(payload), version)

